//! Spec-compliance tests: contextualSpacing semantics, autospacing, and
//! paragraph spacing attributes (ECMA-376 §17.3.1.9, §17.3.1.33).
//!
//! Tests marked `#[ignore]` document known gaps where the implementation
//! diverges from the spec.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/spacing-contextual/create_docs.py`.

use std::fs;
use std::io::{Cursor, Read as _};

use stemma::{DocxRuntime, ExportMode, LineSpacingRule, SimpleRuntime, TransactionMeta};
use zip::ZipArchive;

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/spacing-contextual";

// ── helpers ─────────────────────────────────────────────────────────────

fn import_pair(
    fixtures: &str,
    name: &str,
) -> (SimpleRuntime, stemma::ImportResult, stemma::ImportResult) {
    let before_path = format!("{fixtures}/{name}/before.docx");
    let after_path = format!("{fixtures}/{name}/after.docx");
    let before_bytes = fs::read(&before_path).unwrap_or_else(|e| panic!("read {before_path}: {e}"));
    let after_bytes = fs::read(&after_path).unwrap_or_else(|e| panic!("read {after_path}: {e}"));
    let runtime = SimpleRuntime::new();
    let import_before = runtime
        .import_docx(&before_bytes)
        .unwrap_or_else(|e| panic!("import {before_path}: {e:?}"));
    let import_after = runtime
        .import_docx(&after_bytes)
        .unwrap_or_else(|e| panic!("import {after_path}: {e:?}"));
    (runtime, import_before, import_after)
}

fn extract_document_xml(docx_bytes: &[u8]) -> String {
    let cursor = Cursor::new(docx_bytes);
    let mut zip = ZipArchive::new(cursor).expect("open zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

// ── Test 1: contextualSpacing suppresses between same style ─────────────

/// ECMA-376 §17.3.1.9: When contextualSpacing is on and two consecutive
/// paragraphs share the same pStyle, space between them is suppressed.
///
/// Both paragraphs should import with `contextual_spacing = true`.
#[test]
fn spec_contextual_spacing_suppresses_between_same_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "contextual-same-style");
    let paras = common::all_paragraphs(&doc);

    // Find paragraphs with style CtxSameStyle
    let ctx_paras: Vec<_> = paras
        .iter()
        .filter(|p| p.style_id.as_deref() == Some("CtxSameStyle"))
        .collect();

    assert!(
        ctx_paras.len() >= 2,
        "expected at least 2 paragraphs with style CtxSameStyle, got {}. \
         Paragraphs found: {:?}",
        ctx_paras.len(),
        paras
            .iter()
            .map(|p| p.style_id.as_deref())
            .collect::<Vec<_>>()
    );

    for (i, p) in ctx_paras.iter().enumerate() {
        assert_eq!(
            p.contextual_spacing,
            Some(true),
            "paragraph {} with CtxSameStyle should have contextual_spacing=Some(true), \
             but it is {:?}. The style defines contextualSpacing but it may not \
             have been resolved through the style chain.",
            i,
            p.contextual_spacing
        );
    }
}

// ── Test 2: contextualSpacing explicit false overrides style ────────────

/// ECMA-376 §17.3.1.9: Direct `<w:contextualSpacing w:val="0"/>` on a
/// paragraph should override the style's contextualSpacing=true.
///
/// The import pipeline uses `Option<bool>` for contextualSpacing during
/// resolution: the direct `Some(false)` should win over the style's `true`.
#[test]
fn spec_contextual_spacing_explicit_false_overrides_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "contextual-explicit-false");
    let paras = common::all_paragraphs(&doc);

    // P0: direct contextualSpacing val="0" -> should be false
    let p0 = paras
        .iter()
        .find(|p| {
            let text = common::paragraph_text(p);
            text.contains("P0")
        })
        .expect("should find P0 paragraph");

    assert_eq!(
        p0.contextual_spacing,
        Some(false),
        "P0 has direct contextualSpacing val='0' which should override \
         the style's true, but contextual_spacing is {:?}. \
         The import may not be parsing val='0' correctly, or \
         style resolution may not respect direct false.",
        p0.contextual_spacing
    );

    // P1: no direct override, inherits from style -> should be true
    let p1 = paras
        .iter()
        .find(|p| {
            let text = common::paragraph_text(p);
            text.contains("P1")
        })
        .expect("should find P1 paragraph");

    assert_eq!(
        p1.contextual_spacing,
        Some(true),
        "P1 has no direct contextualSpacing override and should inherit \
         true from CtxStyle, but contextual_spacing is {:?}.",
        p1.contextual_spacing
    );
}

// ── Test 3: contextualSpacing false roundtrip ───────────────────────────

/// ECMA-376 §17.3.1.9: Explicit `contextualSpacing val="0"` must survive
/// a diff/redline roundtrip.
///
/// The "before" doc has contextualSpacing=true (from style). The "after"
/// doc adds a direct `contextualSpacing val="0"` override. After
/// diff_and_redline + export, the output should contain `w:val="0"` on the
/// contextualSpacing element.
///
/// The domain model uses `contextual_spacing: Option<bool>`, allowing
/// the serializer to emit `<w:contextualSpacing w:val="0"/>` for
/// `Some(false)` and nothing for `None`.
#[test]
fn spec_contextual_spacing_false_roundtrip() {
    let (runtime, import_before, import_after) =
        import_pair(FIXTURES, "contextual-false-roundtrip");

    // Verify the "after" doc imports with contextual_spacing=false
    let after_view = runtime.view(&import_after.doc_handle).expect("view after");
    let after_paras = common::all_paragraphs(&after_view.canonical);
    let after_p = after_paras
        .iter()
        .find(|p| p.style_id.as_deref() == Some("CtxRT"))
        .expect("should find paragraph with CtxRT style in after doc");
    assert_eq!(
        after_p.contextual_spacing,
        Some(false),
        "after doc paragraph should have contextual_spacing=Some(false) (direct val='0')"
    );

    // Perform diff and redline
    let meta = TransactionMeta {
        author: "spec_spacing_contextual".to_string(),
        reason: Some("contextual spacing roundtrip test".to_string()),
        timestamp_utc: Some("2025-01-15T10:30:00Z".to_string()),
    };
    let apply = runtime
        .diff_and_redline(&import_before.doc_handle, &import_after.doc_handle, meta)
        .expect("diff_and_redline");
    assert!(apply.applied, "redline should be applied");

    // Export and check the output XML
    let exported = runtime
        .export_docx(&import_before.doc_handle, ExportMode::Redline)
        .expect("export");
    let doc_xml = extract_document_xml(&exported);

    // The output should contain contextualSpacing with val="0"
    assert!(
        doc_xml.contains("contextualSpacing") && doc_xml.contains("val=\"0\""),
        "exported document.xml should contain contextualSpacing with val='0' \
         to override the style's true, but the serializer only emits \
         presence/absence (bool), losing the explicit false. \
         XML snippet around contextualSpacing: {}",
        find_context(&doc_xml, "contextualSpacing")
    );
}

// ── Test 4: beforeAutospacing parsed ────────────────────────────────────

/// ECMA-376 §17.3.1.33: beforeAutospacing overrides the before value.
///
/// When `beforeAutospacing="1"` is set on w:spacing, the `before` value
/// is preserved for roundtrip fidelity but is semantically ignored —
/// the consumer determines spacing automatically.
#[test]
fn spec_before_autospacing_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "before-autospacing");
    let paras = common::all_paragraphs(&doc);

    // P0: before=200 with beforeAutospacing=1
    let p0 = paras
        .iter()
        .find(|p| {
            let text = common::paragraph_text(p);
            text.contains("P0")
        })
        .expect("should find P0 paragraph");

    let sp0 = p0.spacing.as_ref().expect("P0 should have spacing");
    // §17.3.1.33: beforeAutospacing=1 means before is semantically ignored.
    // The raw value is preserved for roundtrip, but the flag signals the override.
    assert_eq!(
        sp0.before_autospacing,
        Some(true),
        "P0 has beforeAutospacing=1, so before_autospacing should be Some(true)"
    );
    // Raw value preserved for roundtrip fidelity
    assert_eq!(
        sp0.before,
        Some(200),
        "P0 before raw value preserved for roundtrip"
    );

    // P1: control — no autospacing, before=200 should be preserved
    let p1 = paras
        .iter()
        .find(|p| {
            let text = common::paragraph_text(p);
            text.contains("P1")
        })
        .expect("should find P1 paragraph");

    let sp1 = p1.spacing.as_ref().expect("P1 should have spacing");
    assert_eq!(
        sp1.before,
        Some(200),
        "P1 (control) should have before=200, got {:?}",
        sp1.before
    );
    assert!(
        sp1.before_autospacing.is_none() || sp1.before_autospacing == Some(false),
        "P1 (control) should not have beforeAutospacing set"
    );
}

