// ── Test 6: basic before/after spacing ──────────────────────────────────

/// ECMA-376 §17.3.1.33: Basic spacing before and after values.
///
/// Control test: paragraph with `spacing before="240" after="200"`.
#[test]
fn spec_spacing_before_after_basic() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-before-after-basic");
    let paras = common::all_paragraphs(&doc);

    let p0 = paras
        .iter()
        .find(|p| {
            let text = common::paragraph_text(p);
            text.contains("P0")
        })
        .expect("should find P0 paragraph");

    let spacing = p0
        .spacing
        .as_ref()
        .expect("P0 should have spacing (before=240, after=200 in XML)");

    assert_eq!(
        spacing.before,
        Some(240),
        "P0 before should be 240, got {:?}",
        spacing.before
    );
    assert_eq!(
        spacing.after,
        Some(200),
        "P0 after should be 200, got {:?}",
        spacing.after
    );
}

// ── Test 7: line spacing auto (single) ──────────────────────────────────

/// ECMA-376 §17.3.1.33: line=240 lineRule=auto means single spacing.
///
/// 240 in auto mode = 240/240 = 1.0 lines = single spacing.
#[test]
fn spec_spacing_line_auto_single() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-line-auto");
    let paras = common::all_paragraphs(&doc);

    let p0 = paras
        .iter()
        .find(|p| {
            let text = common::paragraph_text(p);
            text.contains("P0")
        })
        .expect("should find P0 paragraph");

    let spacing = p0
        .spacing
        .as_ref()
        .expect("P0 should have spacing (line=240 lineRule=auto in XML)");

    assert_eq!(
        spacing.line,
        Some(240),
        "P0 line should be 240 (single spacing in auto mode), got {:?}",
        spacing.line
    );
    assert_eq!(
        spacing.line_rule,
        Some(LineSpacingRule::Auto),
        "P0 lineRule should be Auto, got {:?}",
        spacing.line_rule
    );
}

// ── Test 8: line spacing exact ──────────────────────────────────────────

/// ECMA-376 §17.3.1.33: line=360 lineRule=exact means exactly 18pt.
///
/// In exact mode, the line value is in twips. 360 twips = 18pt.
/// Text may be clipped if it exceeds this height.
#[test]
fn spec_spacing_line_exact() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-line-exact");
    let paras = common::all_paragraphs(&doc);

    let p0 = paras
        .iter()
        .find(|p| {
            let text = common::paragraph_text(p);
            text.contains("P0")
        })
        .expect("should find P0 paragraph");

    let spacing = p0
        .spacing
        .as_ref()
        .expect("P0 should have spacing (line=360 lineRule=exact in XML)");

    assert_eq!(
        spacing.line,
        Some(360),
        "P0 line should be 360 (18pt in exact mode), got {:?}",
        spacing.line
    );
    assert_eq!(
        spacing.line_rule,
        Some(LineSpacingRule::Exact),
        "P0 lineRule should be Exact, got {:?}",
        spacing.line_rule
    );
}

// ── helper ──────────────────────────────────────────────────────────────

/// Find a snippet of XML around a search term for diagnostics.
fn find_context(xml: &str, needle: &str) -> String {
    if let Some(pos) = xml.find(needle) {
        let start = pos.saturating_sub(80);
        let end = (pos + needle.len() + 80).min(xml.len());
        format!("...{}...", &xml[start..end])
    } else {
        format!("('{needle}' not found in XML)")
    }
}
